import React from 'react';
import { BrowserRouter, Route, Routes } from 'react-router-dom';

// Componentes Principais
import Header from '../components/Header/Header.jsx';
import Footer from '../components/Footer/Footer.jsx';
import PrivateRoute from '../components/Auth/Auth.jsx'; // Caminho explícito

// Páginas Públicas
import Inicio from '../pages/Inicio/Inicio.jsx';
import Login from '../pages/Login/Login.jsx';
import Socios from '../pages/Socios/Socios.jsx';
import Vakinha from '../pages/Vakinha/Vakinha.jsx'; // Corrigido para 'Vakinha'
import Adote from '../pages/Adote/Adote.jsx';
import Localizacao from '../pages/Localizacao/Localizacao.jsx';
import Doacao from '../pages/Doacao/Doacao.jsx';
import Empresas from '../pages/Empresas/Empresas.jsx';
import Castracao from '../pages/Castracao/Castracao.jsx';

// Páginas Privadas (requerem login)
import Painel from '../pages/Painel/Painel.jsx';

function App() {
  return (
    <BrowserRouter>
      <div>
        <Header />
        <main>
          <Routes>
            {/* Rotas Públicas */}
            <Route path="/" element={<Inicio />} />
            <Route path="/login" element={<Login />} />
            <Route path="/socios" element={<Socios />} />
            <Route path="/vakinha" element={<Vakinha />} />
            <Route path="/adote" element={<Adote />} />
            <Route path="/localizacao" element={<Localizacao />} />
            <Route path="/doacao" element={<Doacao />} />
            <Route path="/empresas" element={<Empresas />} />
            <Route path="/castracao" element={<Castracao />} />

            {/* Rota Privada */}
            <Route 
              path="/painel" 
              element={
                <PrivateRoute>
                  <Painel />
                </PrivateRoute>
              } 
            />
          </Routes>
        </main>
        <Footer />
      </div>
    </BrowserRouter>
  );
}

export default App;
